 19	import PrometheusGraph from '@utils/components/Area/components/PrometheusGraph';
 20	import PrometheusGraphLink from '@utils/components/Area/components/PrometheusGraphLink';
 21	import useRefWidth from '@utils/components/Area/hooks/useRefWidth';
 22	import { DEFAULT_HEIGHT, DEFAULT_TICK_COUNT } from '@utils/components/Area/utils/constants';
 23	import { DataPoint } from '@utils/components/Area/utils/types';
 24	import { getLegendData, processFrame, timeFormatter } from '@utils/components/Area/utils/utils';
 25	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 26	
 27	import { humanizeNumber } from '../../../../utils/utils/units';
 28	import { areaTheme } from '../utils/themes';
 29	
 30	export type AreaChartProps = {
 31	  ariaChartLinkLabel?: string;
 32	  ariaChartTitle?: string;
 33	  byteDataType?: ByteDataTypes; //Use this to process the whole data frame at once
 34	  chartStyle?: object[];
 35	  className?: string;
 36	  data?: DataPoint[][];
 37	  domain?: ChartAreaProps['domain'];
 38	  formatDate?: (date: Date, showSeconds?: boolean) => string;
 39	  height?: number;
 40	  humanize?: Humanize;
 41	  loading?: boolean;
 42	  mainDataName?: string;
 43	  padding?: object;
 44	  query?: string | string[];
 45	  showAllTooltip?: boolean;
 46	  theme?: any; // TODO figure out the best way to import VictoryThemeDefinition
 47	  tickCount?: number;
 48	  title?: string;
 49	  xAxis?: boolean;
 50	  yAxis?: boolean;
 51	};
 52	
 53	export const CursorVoronoiContainer = createContainer('cursor', 'voronoi');
 54	
 55	const AreaChart: FC<AreaChartProps> = ({
 56	  ariaChartLinkLabel,
 57	  ariaChartTitle,
 58	  byteDataType = '',
 59	  chartStyle,
 60	  className,
 61	  data = [],
 62	  formatDate = timeFormatter.format,
 63	  height = DEFAULT_HEIGHT,
 64	  humanize = humanizeNumber,
 65	  loading = true,
 66	  mainDataName,
 67	  padding,
 68	  query,
 69	  showAllTooltip,
 70	  tickCount = DEFAULT_TICK_COUNT,
 71	  title,
 72	  xAxis = true,
 73	  yAxis = true,
 74	  ...rest
 75	}) => {
 76	  const { t } = useNetworkingTranslation();
 77	  const [containerRef, width] = useRefWidth();
 78	
 79	  const { processedData, unit } = useMemo(() => {
 80	    const nonEmptyDataSets = data.filter((dataSet) => dataSet?.length);
 81	    if (byteDataType) {
 82	      return processFrame(nonEmptyDataSets, byteDataType);
 83	    }
 84	    return { processedData: nonEmptyDataSets, unit: '' };
 85	  }, [byteDataType, data]);
 86	
 87	  // If every data point of every data set is 0, force y-domain to [0,1]
 88	  const allZero = useMemo(
 89	    () => _.every(processedData, (dataSet) => _.every(dataSet, ({ y }) => y === 0)),
 90	    [processedData],
 91	  );
 92	
 93	  const xTickFormat = useCallback((tick) => formatDate(tick), [formatDate]);
 94	  const yTickFormat = useCallback(
 95	    (tick) => `${humanize(tick, unit, unit).string}`,
 96	    [humanize, unit],
 97	  );
 98	
 99	  const domain = useMemo<AreaChartProps['domain']>(
100	    () => ({
101	      ...(allZero && { y: [0, 1] }),
102	      ...(rest.domain ?? {}),
103	    }),
104	    [allZero, rest.domain],
105	  );
106	
107	  const getLabel = useCallback(
108	    (prop: { datum: DataPoint<Date> }, includeDate = true) => {
109	      const { x, y } = prop.datum;
110	      const value = humanize(y, unit, unit).string;
111	      const date = formatDate(x);
112	      return includeDate ? t('{{value}} at {{date}}', { date, value }) : value;
113	    },
114	    [humanize, unit, formatDate, t],
115	  );
116	
117	  // Note: Victory incorrectly typed ThemeBaseProps.padding as number instead of PaddingProps
118	  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
119	  // @ts-ignore
120	  const theme = getCustomTheme(ChartThemeColor.blue, areaTheme);
121	
122	  const multiLine = processedData?.length > 1;
123	
124	  const container = useMemo(() => {
125	    if (multiLine) {
126	      const legendData = getLegendData(processedData);
127	
128	      return (
129	        <CursorVoronoiContainer
130	          activateData={false}
131	          cursorDimension="x"
132	          labelComponent={
133	            <ChartLegendTooltip
134	              formatDate={(d) => formatDate(d[0].x)}
135	              getLabel={getLabel}
136	              legendData={legendData}
137	              mainDataName={mainDataName}
138	              stack={showAllTooltip}
139	            />
140	          }
141	          labels={(props) => getLabel(props, false)}
142	          mouseFollowTooltips
143	          voronoiDimension="x"
144	        />
145	      );
146	    }
147	    return <ChartVoronoiContainer activateData={false} labels={getLabel} voronoiDimension="x" />;
148	  }, [formatDate, getLabel, mainDataName, multiLine, processedData, showAllTooltip]);
149	
150	  return (
151	    <PrometheusGraph className={className} ref={containerRef} title={title}>
152	      <PrometheusGraphLink ariaChartLinkLabel={ariaChartLinkLabel} query={query}>
153	        {processedData?.length ? (
154	          <Chart
155	            ariaTitle={ariaChartTitle || title}
156	            containerComponent={container}
157	            domain={domain}
158	            domainPadding={{ y: 20 }}
159	            height={height}
160	            padding={padding}
161	            scale={{ x: 'time', y: 'linear' }}
162	            theme={theme}
163	            width={width}
164	          >
165	            {xAxis && <ChartAxis tickCount={tickCount} tickFormat={xTickFormat} />}
166	            {yAxis && <ChartAxis dependentAxis tickCount={tickCount} tickFormat={yTickFormat} />}
167	            <ChartGroup>
168	              {processedData.map((datum, index) => (
169	                <ChartArea
170	                  data={datum}
171	                  key={index}
172	                  name={datum[0]?.description}
173	                  style={chartStyle && chartStyle[index]}
174	                />
175	              ))}
176	            </ChartGroup>
177	          </Chart>
178	        ) : (
179	          <GraphEmpty height={height} loading={loading} />
180	        )}
181	      </PrometheusGraphLink>
182	    </PrometheusGraph>
183	  );
184	};
185	
186	export default AreaChart;

